/*
 * mm_realloc: Resize the block pointed to by ptr to at least 'size' bytes.
 *
 * Tries in-place extension before falling back to malloc+copy:
 *   1. If shrinking: split in place (if remainder >= min block size).
 *   2. If growing and next block is free with enough combined space: absorb it.
 *   3. If growing and next block is free at end of heap (epilogue after it):
 *      absorb the free block + extend heap by exactly the shortfall.
 *   4. If next block IS the epilogue: extend heap by exactly what's needed.
 *   5. Fallback: malloc new block, copy, free old.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t oldsize, asize, combined, needed;
	void *newptr, *next_bp;
	bool next_alloc;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	if (ptr == NULL)
		return (mm_malloc(size));

	/* Adjusted requested size */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	oldsize = GET_SIZE(HDRP(ptr));

	/* Case 1: New size fits in current block — optionally split */
	if (asize <= oldsize) {
		if (oldsize - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(oldsize - asize, 0));
			PUT(FTRP(next_bp), PACK(oldsize - asize, 0));
			coalesce(next_bp);
		}
		return (ptr);
	}

	next_bp = NEXT_BLKP(ptr);
	next_alloc = GET_ALLOC(HDRP(next_bp));
	combined = oldsize + GET_SIZE(HDRP(next_bp));

	/* Case 2: Next block is free and large enough — absorb it */
	if (!next_alloc && combined >= asize) {
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 3: Next block is free but not enough, and it's at the end of heap.
	 * Absorb the free block and extend the heap by exactly the shortfall.
	 * extend_heap will automatically coalesce with the free block. */
	if (!next_alloc && GET_SIZE(HDRP(NEXT_BLKP(next_bp))) == 0) {
		needed = asize - combined;
		if (extend_heap(needed / WSIZE) == NULL)
			return (NULL);
		/* next_bp has been enlarged by coalescing with the extension */
		combined = oldsize + GET_SIZE(HDRP(next_bp));
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 4: Next block is the epilogue — extend heap by exactly what's needed */
	if (GET_SIZE(HDRP(next_bp)) == 0) {
		needed = asize - oldsize;
		if (extend_heap(needed / WSIZE) == NULL)
			return (NULL);
		/* next_bp is now a free block of size == needed */
		combined = oldsize + GET_SIZE(HDRP(next_bp));
		remove_free(next_bp);
		if (combined - asize >= 2 * DSIZE) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			next_bp = NEXT_BLKP(ptr);
			PUT(HDRP(next_bp), PACK(combined - asize, 0));
			PUT(FTRP(next_bp), PACK(combined - asize, 0));
			insert_free(next_bp);
		} else {
			PUT(HDRP(ptr), PACK(combined, 1));
			PUT(FTRP(ptr), PACK(combined, 1));
		}
		return (ptr);
	}

	/* Case 5: Fallback — allocate new block, copy payload, free old block */
	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);
	size_t copysize = oldsize - DSIZE;
	if (size < copysize)
		copysize = size;
	memcpy(newptr, ptr, copysize);
	mm_free(ptr);
	return (newptr);
}

